import { TIME_UNITS_PATTERN, parseDuration } from "../constants.js";
import { ParsingComponents } from "../../../results.js";
import { AbstractParserWithWordBoundaryChecking } from "../../../common/parsers/AbstractParserWithWordBoundary.js";
class NLTimeUnitWithinFormatParser extends AbstractParserWithWordBoundaryChecking {
  innerPattern() {
    return new RegExp(`(?:binnen|in|binnen de|voor)\\s*` + "(" + TIME_UNITS_PATTERN + ")" + `(?=\\W|$)`, "i");
  }
  innerExtract(context, match) {
    const timeUnits = parseDuration(match[1]);
    return ParsingComponents.createRelativeFromReference(context.reference, timeUnits);
  }
}

export { NLTimeUnitWithinFormatParser as default };